import { useEffect, useState } from "react";
import ListOnLesson from "../../Components/Lists/ListOnLesson";
import MainBtns from "../../Components/Buttons/MainBtns";
import HeaderOnLesson from "../../Components/Header/HeaderOnLesson";

import { toast } from "react-toastify";
import config from "../../config.json";
import axios from "axios";
import { useParams } from "react-router-dom";

import ReactMarkdown from "react-markdown"

function LearnCoursePage() {
  const [materials, setMaterials] = useState([]);
  const [text, setText] = useState();

  const id = useParams().id;
  const idLesson = useParams().idLesson;
  
  useEffect(() => {
    let cancelled = false;

    async function load() {
      try {
        // 1) контент урока
        const textRes = await axios.get(`${config.BaseURL}/modules/${id}/lessons/${idLesson}/content`, { withCredentials: true });
        if (!cancelled) setText(textRes.data);

        // 2) попытка получить модуль, чтобы узнать courseId
        let courseId;
        try {
          const moduleRes = await axios.get(`${config.BaseURL}/modules/${id}`, { withCredentials: true });
          courseId = moduleRes.data?.CourseId || moduleRes.data?.courseId || moduleRes.data?.Course?.Id;
        } catch (e) {
          // если /modules/:id недоступен, оставим courseId пустым
          courseId = null;
        }

        // 3) если не получили courseId — попытаемся использовать id как courseId
        if (!courseId) courseId = id;

        // 4) получить данные курса и выставить материалы (ожидаем Modules или modules)
        try {
          const courseRes = await axios.get(`${config.BaseURL}/courses/${courseId}`, { withCredentials: true });
          const courseData = courseRes.data;
          const modules = courseData?.Modules || courseData?.modules || [];

          // Приведём формат к тому, что ожидает список материалов в компоненте
          // Если локальный файл был массивом объектов с полем materialOfCourse,
          // то преобразуем модули в подобный формат: { materialOfCourse: module }
          const materialsPayload = Array.isArray(modules)
            ? modules.map((m) => ({ materialOfCourse: m }))
            : [];

          if (!cancelled) setMaterials(materialsPayload);
        } catch (e) {
          console.error('Ошибка загрузки курса:', e);
        }
      } catch (err) {
        console.error(err);
        switch (err.response?.status) {
          case 404:
            toast.error('Не найден ресурс');
            break;
          case 500:
            toast.error('Ошибка сервера');
            break;
          default:
            toast.error('Ошибка загрузки');
        }
      }
    }

    load();
    return () => {
      cancelled = true;
    };
  }, [id, idLesson]);

  return (
    <div className="learn-page">
      
      <HeaderOnLesson/>
      <div className="learn-page-body">
        <div className="left-panel">
          <ul>
            {materials.map((item,index)=> (
              <li key={index}>
                <ListOnLesson data={item.materialOfCourse}/>
              </li>
            ))}
          </ul>
        </div>

        <div className="main-info">
          <div className="markdown-box">
            <ReactMarkdown urlTransform={(url) =>
                `${config.BaseURL}/modules/${id}/lessons/${idLesson}/files/${url}`
            }>
              {text}
            </ReactMarkdown>
          </div>
          <div className="bottom-area">
            <MainBtns Style={"null-btn"} Height={"50px"} Width={"100px"} Text={"Далее"} ZIndex={"2"}/>
            <div className="backgroung-image"></div>
          </div>
        </div>
      </div>
    </div>
  );
}

export default LearnCoursePage;
